SELECT rental_date, rent 
FROM property_rentals 
WHERE property_id = 0;

SELECT SUM(tax_amount) 
FROM property_tax_records 
WHERE property_id = 1 AND tax_year = 2022;

SELECT COUNT(property_id) AS total_properties_sold
FROM property_sales
WHERE seller = (SELECT user_name FROM users WHERE email = 'bob.williams@example.com');

SELECT AVG(average_value) 
FROM market_trends 
WHERE zip_code = '0';
